import{_ as a,o as e,c as l,ai as i}from"./chunks/framework.CsYGeNYI.js";const k=JSON.parse('{"title":"创建 Skills","description":"","frontmatter":{"title":"创建 Skills","x-i18n":{"generated_at":"2026-02-03T10:10:19Z","model":"claude-opus-4-5","provider":"pi","source_hash":"ad801da34fe361ffa584ded47f775d1c104a471a3f7b7f930652255e98945c3a","source_path":"tools/creating-skills.md","workflow":15}},"headers":[],"relativePath":"zh-CN/tools/creating-skills.md","filePath":"zh-CN/tools/creating-skills.md","lastUpdated":1771906665000}'),n={name:"zh-CN/tools/creating-skills.md"};function t(r,s,o,h,p,d){return e(),l("div",null,[...s[0]||(s[0]=[i(`<h1 id="创建自定义-skills-🛠" tabindex="-1"><a class="header-anchor" href="#创建自定义-skills-🛠">#</a> 创建自定义 Skills 🛠</h1><p>OpenSoul 被设计为易于扩展。&quot;Skills&quot;是为你的助手添加新功能的主要方式。</p><h2 id="什么是-skill" tabindex="-1"><a class="header-anchor" href="#什么是-skill">#</a> 什么是 Skill？</h2><p>Skill 是一个包含 <code>SKILL.md</code> 文件（为 LLM 提供指令和工具定义）的目录，可选包含一些脚本或资源。</p><h2 id="分步指南-你的第一个-skill" tabindex="-1"><a class="header-anchor" href="#分步指南-你的第一个-skill">#</a> 分步指南：你的第一个 Skill</h2><h3 id="_1-创建目录" tabindex="-1"><a class="header-anchor" href="#_1-创建目录">#</a> 1. 创建目录</h3><p>Skills 位于你的工作区中，通常是 <code>~/.opensoul/workspace/skills/</code>。为你的 Skill 创建一个新文件夹：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.opensoul/workspace/skills/hello-world</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_2-定义-skill-md" tabindex="-1"><a class="header-anchor" href="#_2-定义-skill-md">#</a> 2. 定义 <code>SKILL.md</code></h3><p>在该目录中创建一个 <code>SKILL.md</code> 文件。此文件使用 YAML frontmatter 作为元数据，使用 Markdown 作为指令。</p><div class="language-markdown vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">hello_world</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">A simple skill that says hello.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># Hello World Skill</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">When the user asks for a greeting, use the </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\`echo\`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> tool to say &quot;Hello from your custom skill!&quot;.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="_3-添加工具-可选" tabindex="-1"><a class="header-anchor" href="#_3-添加工具-可选">#</a> 3. 添加工具（可选）</h3><p>你可以在 frontmatter 中定义自定义工具，或指示智能体使用现有的系统工具（如 <code>bash</code> 或 <code>browser</code>）。</p><h3 id="_4-刷新-opensoul" tabindex="-1"><a class="header-anchor" href="#_4-刷新-opensoul">#</a> 4. 刷新 OpenSoul</h3><p>让你的智能体&quot;刷新 skills&quot;或重启 Gateway 网关。OpenSoul 将发现新目录并索引 <code>SKILL.md</code>。</p><h2 id="最佳实践" tabindex="-1"><a class="header-anchor" href="#最佳实践">#</a> 最佳实践</h2><ul><li><strong>简洁明了</strong>：指示模型<em>做什么</em>，而不是如何成为一个 AI。</li><li><strong>安全第一</strong>：如果你的 Skill 使用 <code>bash</code>，确保提示词不允许来自不受信任用户输入的任意命令注入。</li><li><strong>本地测试</strong>：使用 <code>opensoul agent --message &quot;use my new skill&quot;</code> 进行测试。</li></ul><h2 id="共享-skills" tabindex="-1"><a class="header-anchor" href="#共享-skills">#</a> 共享 Skills</h2><p>你也可以在 <a href="https://clawhub.com" target="_blank" rel="noreferrer">ClawHub</a> 上浏览和贡献 Skills。</p>`,19)])])}const u=a(n,[["render",t]]);export{k as __pageData,u as default};
